# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _baseDirectory = Path.Combine(Directory.GetCurrentDirectory(), "uploads");

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrEmpty(filename))
                return BadRequest("Filename is required.");

            var fullPath = Path.Combine(_baseDirectory, filename);

            // Canonicalize and validate the file path
            if (!Path.IsPathCanonicalized(fullPath) || !fullPath.StartsWith(_baseDirectory))
                return NotFound();

            if (!System.IO.File.Exists(fullPath))
                return NotFound();

            var fileInfo = new FileInfo(fullPath);
            var contentType = GetContentType(fileInfo.Extension);

            return PhysicalFile(fullPath, contentType);
        }

        private string GetContentType(string extension)
        {
            switch (extension.ToLower())
            {
                case ".doc":
                case ".docx":
                    return "application/msword";
                case ".pdf":
                    return "application/pdf";
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".png":
                    return "image/png";
                // Add more content types as needed
                default:
                    return "application/octet-stream";
            }
        }
    }
}